import{_ as o,o as s,c as r,a2 as n}from"./chunks/framework.BWuWLRhz.js";const d="/assets/30-feature-decision-tree@2x.DqM-B0uq.png",k=JSON.parse('{"title":"30 · 功能怎么选：CLAUDE.md vs Skill vs Hook vs MCP vs Subagent","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/30-choosing-features.md","filePath":"claude-code/30-choosing-features.md"}'),g={name:"claude-code/30-choosing-features.md"};function l(e,t,a,p,i,h){return s(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="_30-·-功能怎么选-claude-md-vs-skill-vs-hook-vs-mcp-vs-subagent" tabindex="-1">30 · 功能怎么选：CLAUDE.md vs Skill vs Hook vs MCP vs Subagent <a class="header-anchor" href="#_30-·-功能怎么选-claude-md-vs-skill-vs-hook-vs-mcp-vs-subagent" aria-label="Permalink to &quot;30 · 功能怎么选：CLAUDE.md vs Skill vs Hook vs MCP vs Subagent&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./29-agent-teams">29 Agent teams 智能体团队</a> 教你用 Agent teams 开多智能体并行协作。这一篇给整个第四组收口——CLAUDE.md、Skill、Hook、MCP、Subagent 一路学下来，全堆在脑子里反而容易选错。我给你一张决策表加一棵决策树，<strong>对着「需求」直接查「该用哪个」，再不纠结</strong>。</p></blockquote><p>兄弟们，学到这儿，你手里已经攒了一堆扩展点了。</p><p>CLAUDE.md、Skill、Hook、MCP、Subagent，外加随处可见的斜杠命令（slash command），五六个名词，每个单看都懂。<strong>但真到「我这个需求，该用哪个」的时候，十有八九会卡壳。</strong> 刚学完这套的人，最常冒出来的一句就是「这个用 Skill 还是 Subagent 啊？」「这事儿我写进 CLAUDE.md 行不行？」</p><p>说白了，这不是知识不够，是<strong>没建立「需求 → 方案」的映射</strong>。每个扩展点的官方介绍你都读过，但它们是按「这是什么」组织的，不是按「你想干嘛」组织的。这一篇就反过来——<strong>从你的需求出发，倒推该用哪个</strong>。</p><p>这么说吧：前面九篇是把五件兵器一件件递到你手上，这一篇是教你<strong>临阵该抽哪把</strong>。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>五大扩展点（外加 slash command）各自「解决什么、什么时候选、什么时候别用」的一句话定位</li><li>一张「需求 → 推荐方案」决策表，对症查方案</li><li>一棵能照着走的决策树，三四个问题问下来就锁定该用哪个</li><li>几组最容易混的对比（Skill vs Subagent、CLAUDE.md vs Skill、Hook vs 权限规则）一次讲透</li><li>知道这些扩展点怎么组合、怎么用 plugin 打包带走</li></ul><hr><h2 id="_01-先建一个总框架-六个扩展点插在「代理循环」的不同位置" tabindex="-1">01 先建一个总框架：六个扩展点插在「代理循环」的不同位置 <a class="header-anchor" href="#_01-先建一个总框架-六个扩展点插在「代理循环」的不同位置" aria-label="Permalink to &quot;01 先建一个总框架：六个扩展点插在「代理循环」的不同位置&quot;">​</a></h2><p>动手挑之前，先在脑子里搭个总架子。<strong>这些扩展点不是平行的六个选项，而是插在 Claude 工作流程不同环节上的六个挂钩。</strong></p><p>回想第 03 篇讲的「代理循环」——Claude 干活就是「想 → 做 → 看」转圈。这六个扩展点（CLAUDE.md、Skill、slash command、MCP、Subagent、Hook），正好插在这个循环的不同位置：有的在「想」之前塞进背景，有的在「做」的时候接外部、开分身，有的在某个固定时刻自动扣扳机。官方那句话点得很准，值得先记住：</p><blockquote><p>扩展插入代理循环的不同部分。</p></blockquote><p><strong>类比：医院的分诊台。</strong> 你身体不舒服去医院，不会自己冲进某个科室，先到分诊台说「症状」——头疼挂神经内科、肚子疼挂消化科、要拍片去影像科。分诊台不治病，它干的是<strong>照你的症状把你导向对的科室</strong>。这一篇我就是给你当这个分诊台：你报「需求」，我把你导向对的「扩展点」。</p><p>落到真实场景，你纠结的往往就那几句话：「我想让它<strong>每次都遵守</strong>某条规矩」「让它<strong>需要时自动调出</strong>某项专长」「让某件事在<strong>特定时机自动发生</strong>」「让它<strong>连上外部数据或服务</strong>」。需求一旦说清，挂哪个科其实没那么难。下面几节，逐个把「科室」介绍清楚，最后给你一张总表加一棵树。</p><blockquote><p>💡 一句话总结：六个扩展点不是六选一的平行选项，而是<strong>插在「想→做→看」不同环节上的挂钩</strong>；选的关键不是「哪个厉害」，而是「你的需求该挂哪个」。</p></blockquote><hr><h2 id="_02-六个科室-一句话认清各自的「主治」" tabindex="-1">02 六个科室，一句话认清各自的「主治」 <a class="header-anchor" href="#_02-六个科室-一句话认清各自的「主治」" aria-label="Permalink to &quot;02 六个科室，一句话认清各自的「主治」&quot;">​</a></h2><p>先把六个扩展点的「主治范围」一句话钉住。这一节是地基，下面的决策表全建在它上面。我按官方那张功能表的口径，给每个配一个最典型的场景。</p><p><strong>CLAUDE.md —— 让它「每次都记住」的规矩。</strong> 项目约定、构建命令、「永远用 pnpm 不用 npm」「提交前先跑测试」这类<strong>始终生效</strong>的背景。它每个会话自动加载，Claude 一开工就看得到。</p><p><strong>Skill —— 让它「需要时自动调出」的专项能力。</strong> 可重复用的知识或流程：一份 API 风格指南、一套部署清单、一个调试套路。平时只占描述文本，<strong>用到时才把完整内容调进来</strong>；你也能用 <code>/&lt;name&gt;</code> 主动唤它。</p><p><strong>slash command —— 你「主动一键触发」的固定流程。</strong> 它其实就是 Skill 的一种用法（带 <code>/&lt;name&gt;</code> 触发的那种）。区别只在「谁来发起」：Skill 可以由 Claude 自动判断要不要用，slash command 是<strong>你打 <code>/deploy</code> 主动喊它来</strong>。</p><p><strong>MCP —— 把它「接到外部世界」的接口。</strong> 查你的数据库、发消息到 Slack、控制浏览器——凡是 Claude 内置工具够不着、需要连外部服务或数据的，靠 MCP（详见第 22 篇）。</p><p><strong>Subagent —— 给它开个「独立分身」去干脏活。</strong> 需要读几十个文件、跑大范围搜索，但你只想要个结论、不想让中间过程把主对话塞满时，派个 Subagent 去（详见第 23 篇）。它在隔离的上下文里干，干完<strong>只把摘要递回来</strong>。</p><p><strong>Hook（钩子）—— 在固定时机「自动扣扳机」。</strong> Hook 就是「某个事件一发生就自动跑的一段动作」。某个生命周期事件一触发（比如「每次改完文件」「每次会话开始」），它就<strong>雷打不动</strong>执行——跑 linter、拒掉危险命令、发条通知。它不靠 Claude 思考，触发是<strong>有保证的</strong>。</p><blockquote><p>Hook 这个概念，前面一直没集中讲过，这里先建立个印象就行：<strong>它是「事件触发的自动动作」</strong>。完整的写法、能监听哪些事件，留到第 33 篇专门拆。</p></blockquote><p>光说容易糊，并排放一张表，对照看立刻清楚：</p><table tabindex="0"><thead><tr><th>扩展点</th><th>一句话主治</th><th>谁来触发</th><th>占不占常驻上下文</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td>每次都遵守的项目规矩</td><td>自动，每会话加载</td><td>占（全文常驻）</td></tr><tr><td><strong>Skill</strong></td><td>按需调出的专项知识 / 流程</td><td>Claude 自动判断 <strong>或</strong> 你 <code>/&lt;name&gt;</code></td><td>低（平时只占描述）</td></tr><tr><td><strong>slash command</strong></td><td>主动一键触发的固定流程</td><td>你打 <code>/xxx</code></td><td>低（同 Skill）</td></tr><tr><td><strong>MCP</strong></td><td>连外部服务 / 数据</td><td>Claude 用到工具时</td><td>低（先只占工具名）</td></tr><tr><td><strong>Subagent</strong></td><td>隔离上下文 / 并行专项任务</td><td>你或 Claude 派活</td><td>不占主窗口（独立上下文）</td></tr><tr><td><strong>Hook</strong></td><td>特定事件自动跑固定动作</td><td>生命周期事件</td><td>零（除非它返回输出）</td></tr></tbody></table><p>这张表你不用背，<strong>但「谁来触发」和「占不占常驻上下文」这两列，是后面所有决策的分水岭</strong>——一个决定「是你主动还是它自动」，一个决定「值不值得常开着」。</p><blockquote><p>💡 一句话总结：六个扩展点的「主治」各不相同——<strong>规矩进 CLAUDE.md、专长做 Skill、一键流程是 slash command、外部连接靠 MCP、隔离干活派 Subagent、固定时机自动跑用 Hook</strong>。</p></blockquote><hr><h2 id="_03-决策表-报需求-查方案" tabindex="-1">03 决策表：报需求，查方案 <a class="header-anchor" href="#_03-决策表-报需求-查方案" aria-label="Permalink to &quot;03 决策表：报需求，查方案&quot;">​</a></h2><p>总框架有了，主治认清了，现在上这一篇的核心——<strong>「需求 → 推荐方案」决策表</strong>。用法很简单：左列找一句最像你心里那句话的需求，右列就是该用的扩展点，末列告诉你「为什么是它、别错用成隔壁」。</p><table tabindex="0"><thead><tr><th>你的需求（心里那句话）</th><th>推荐方案</th><th>为什么是它 / 别用错</th></tr></thead><tbody><tr><td>「每次都按我们的约定来」（用 pnpm、提交前跑测试）</td><td><strong>CLAUDE.md</strong></td><td>始终生效的规矩，要它每会话都看到</td></tr><tr><td>「这份 API 文档 / 风格指南，它需要时能查到」</td><td><strong>Skill</strong></td><td>参考资料，平时别占上下文，用到再调</td></tr><tr><td>「我想敲个 <code>/deploy</code> 就跑完整套部署流程」</td><td><strong>slash command</strong>（Skill 的一种）</td><td>你主动触发的固定多步流程</td></tr><tr><td>「让它查我们公司数据库 / 发 Slack」</td><td><strong>MCP</strong></td><td>要连外部服务和数据，内置工具够不着</td></tr><tr><td>「让它读完几十个文件，只给我个结论」</td><td><strong>Subagent</strong></td><td>要上下文隔离，别让中间过程塞爆主窗口</td></tr><tr><td>「这几件事同时查，互不依赖」</td><td><strong>Subagent</strong>（多个并行）</td><td>并行专项任务，各干各的返回摘要</td></tr><tr><td>「每次改完文件，自动跑一遍 ESLint」</td><td><strong>Hook</strong>（<code>PostToolUse</code>）</td><td>固定时机的自动动作，不需要它思考</td></tr><tr><td>「<code>rm -rf /</code> 这种命令，给我硬拦死」</td><td><strong>Hook</strong>（<code>PreToolUse</code>）<strong>或权限规则</strong></td><td>要「保证」拦住，不能靠提示</td></tr><tr><td>「它老忘某条约定，提醒过两次了」</td><td><strong>CLAUDE.md</strong></td><td>反复犯的错，写进常驻规矩，不是聊天里临时纠正</td></tr><tr><td>「同一段开场提示，我天天手打」</td><td><strong>Skill</strong></td><td>重复输入的提示，存成可调用的 Skill</td></tr><tr><td>「这套配置，我想原样搬到另一个项目」</td><td><strong>Plugin</strong>（打包层）</td><td>把 Skill / Hook / Subagent / MCP 捆一起带走</td></tr></tbody></table><p>我把官方「随时间构建你的设置」那张触发器表的精神也揉进去了：<strong>很多需求其实是「重复」逼出来的</strong>——同一句提示打第三遍、同一个错纠正第二次，就是信号，该把它「固化」成对应的扩展点了，别老靠临场嘱咐。</p><p>这里插一个最容易踩的真坑。图省事的话，很容易把一份将近三百行的 API 接口清单<strong>直接塞进 CLAUDE.md</strong>，想着「让它一直记着多方便」。结果呢——每个会话一开就先吞掉一大块上下文，正经活儿还没开始，工作台已经被占走一截；更糟的是 Claude 经常<strong>抓不住你真正强调的那几条核心约定</strong>，被那堆接口细节淹了。把接口清单挪进一个 Skill，CLAUDE.md 只留一句「接口规范见 <code>api-skill</code>」，<strong>世界一下就清净了</strong>。这就是官方反复念叨的那条：</p><blockquote><p>保持 CLAUDE.md 在 200 行以下。如果它在增长，将参考内容移到 skills。</p></blockquote><blockquote><p>💡 一句话总结：拿不准时，<strong>先把需求翻译成「心里那句话」，再来这张表对号入座</strong>；尤其记住「始终生效→CLAUDE.md、按需参考→Skill、外部连接→MCP、隔离干活→Subagent、固定时机→Hook」。</p></blockquote><hr><h2 id="_04-一棵决策树-三四个问题问下来-直接锁定" tabindex="-1">04 一棵决策树：三四个问题问下来，直接锁定 <a class="header-anchor" href="#_04-一棵决策树-三四个问题问下来-直接锁定" aria-label="Permalink to &quot;04 一棵决策树：三四个问题问下来，直接锁定&quot;">​</a></h2><p>表是「已知需求查方案」，但有时候你需求自己都没想太清。这时候用<strong>决策树</strong>更顺——<strong>顺着几个二选一的问题往下走，走到叶子就是答案</strong>。</p><p>我把判断顺序设计成下面这棵树。核心就四个问题，按这个顺序问，基本不会错：</p><p><img src="'+d+`" alt="从需求出发挑扩展点的决策树"></p><p>这张图把「我有个需求，该用哪个扩展点」拆成一条自上而下的问答路径——先问「要不要硬保证/连外部」，再问「该它自动还是你主动」，一路分叉走到底，每个叶子节点就是一个明确的扩展点。</p><p>把这棵树用文字走一遍，你会发现判断顺序其实很自然：</p><p><strong>第一问：这事要「连外部服务或数据」吗？</strong> 要——比如查数据库、发 Slack、控制浏览器——<strong>直接挂 MCP</strong>，到此结束。这一条最好认，先筛掉。</p><p><strong>第二问：这事要「每次都成立、不能靠 Claude 自觉」吗？</strong> 要「保证」级别的强制——比如「<code>.env</code> 绝对不许编辑」「<code>rm -rf /</code> 必须拦」「每次改完文件必须跑 lint」——<strong>用 Hook</strong>（或权限规则，见下一节）。关键词是「<strong>保证</strong>」：Hook 在它的事件上总会触发，是确定的；写进 CLAUDE.md 只是「请求」，Claude 可能照办也可能漏。</p><p><strong>第三问：这事是「一次性的脏活、想隔离」吗？</strong> 要读一堆文件、跑大搜索，只想要结论、不想让过程占满主对话，或者几件事想并行——<strong>派 Subagent</strong>。它在独立上下文里干，干完只递摘要回来。</p><p><strong>走到这儿还没分出去的，就是「知识 / 规矩 / 流程」三选一了，再问最后一个</strong>：</p><p><strong>第四问：它该「每次都看到」，还是「需要时才看」？</strong></p><ul><li>每次都得看到的<strong>规矩</strong>（约定、构建命令、永不做 X）→ <strong>CLAUDE.md</strong>。</li><li>需要时才查的<strong>知识或流程</strong>（API 文档、部署清单、调试套路）→ <strong>Skill</strong>。</li><li>这里头「你想主动一键触发的多步流程」，就让这个 Skill 带上 <code>/&lt;name&gt;</code>，当 <strong>slash command</strong> 用。</li></ul><p>四个问题，从「最好认的外部连接」问到「最微妙的知识 vs 规矩」，<strong>层层筛下来，叶子就是答案</strong>。挑扩展点时，脑子里基本就是默念这四句。</p><blockquote><p>💡 一句话总结：决策树的顺序是「<strong>连外部？→ 要硬保证？→ 要隔离？→ 每次看还是按需看？</strong>」，四问下来直达叶子，比死记一堆定义好用得多。</p></blockquote><hr><h2 id="_05-三组最容易混的-一次讲透" tabindex="-1">05 三组最容易混的，一次讲透 <a class="header-anchor" href="#_05-三组最容易混的-一次讲透" aria-label="Permalink to &quot;05 三组最容易混的，一次讲透&quot;">​</a></h2><p>光有树还不够，<strong>总有那么几对长得像、一选就纠结的</strong>。我挑出新手问得最多的三组，逐一掰开。这三组讲明白了，决策表用起来才不打架。</p><h3 id="skill-vs-subagent" tabindex="-1">Skill vs Subagent <a class="header-anchor" href="#skill-vs-subagent" aria-label="Permalink to &quot;Skill vs Subagent&quot;">​</a></h3><p>这两个最容易混，因为「都能装一套流程」。但它们解决的根本不是一回事。</p><p><strong>类比：手册 vs 外派。</strong> Skill 是一本<strong>可以共享的手册</strong>，谁需要谁翻、翻完内容进的是你当前这本「工作笔记」；Subagent 是<strong>外派一个人</strong>带着任务出去办，办完只回来跟你汇报结论，他在外面翻了多少资料你这边一点不沾。</p><p>核心差别就一个词：<strong>上下文</strong>。</p><table tabindex="0"><thead><tr><th>对比维度</th><th>Skill</th><th>Subagent</th></tr></thead><tbody><tr><td>它是什么</td><td>可复用的知识 / 流程</td><td>有独立上下文的隔离工作者</td></tr><tr><td>内容去哪</td><td>加载进<strong>你的主窗口</strong></td><td>用它<strong>自己的窗口</strong>，结果才回主窗口</td></tr><tr><td>主对话受影响吗</td><td>占用主上下文</td><td>隔离，几乎不占主窗口</td></tr><tr><td>最适合</td><td>参考资料、可调用流程</td><td>读一堆文件的活、并行任务、专项工作者</td></tr></tbody></table><p>一句话切：<strong>要「内容进我这儿用」选 Skill，要「过程别污染我这儿、只给我结论」选 Subagent</strong>。它俩还能合体——Subagent 启动时可以预加载指定的 Skill，等于「外派的人自带专用手册」。</p><h3 id="claude-md-vs-skill" tabindex="-1">CLAUDE.md vs Skill <a class="header-anchor" href="#claude-md-vs-skill" aria-label="Permalink to &quot;CLAUDE.md vs Skill&quot;">​</a></h3><p>这俩都是「存指令」，区别在<strong>加载方式</strong>。</p><table tabindex="0"><thead><tr><th>对比维度</th><th>CLAUDE.md</th><th>Skill</th></tr></thead><tbody><tr><td>什么时候加载</td><td>每个会话，自动</td><td>按需（用到才加载）</td></tr><tr><td>能触发工作流吗</td><td>不能</td><td>能，用 <code>/&lt;name&gt;</code></td></tr><tr><td>最适合</td><td>「始终做 X」的规矩</td><td>参考资料、可调用流程</td></tr></tbody></table><p>判断口诀官方给得很干脆：<strong>「Claude 应该始终知道」的进 CLAUDE.md，「有时才需要查」的进 Skill</strong>。第 03 节那个「三百行接口塞 CLAUDE.md」的坑，本质就是把该进 Skill 的东西错放进了 CLAUDE.md。</p><h3 id="hook-vs-权限规则" tabindex="-1">Hook vs 权限规则 <a class="header-anchor" href="#hook-vs-权限规则" aria-label="Permalink to &quot;Hook vs 权限规则&quot;">​</a></h3><p>这组的纠结点是：<strong>「拦住某个危险操作」到底用 Hook 还是用权限规则（第 20 篇讲的 <code>deny</code>）？</strong></p><p>先说共性：<strong>两者都是「强制级」的硬约束，不靠 Claude 自觉</strong>——这点上它俩站一边，跟「写在 CLAUDE.md 里的请求」泾渭分明。官方那句话点破了关键：</p><blockquote><p>CLAUDE.md 或 skill 中的「永远不要编辑 <code>.env</code>」之类的说明是请求，而不是保证。阻止编辑的 <code>PreToolUse</code> hook 是强制执行。</p></blockquote><p>区别在「<strong>管的面有多宽、做的事有多杂</strong>」：</p><ul><li><strong>权限规则</strong>：声明式，专管「这个工具 / 这条命令，准不准」。在 deny 规则里写一条 <code>Bash(rm -rf *)</code>（即 settings.json 的 <code>&quot;deny&quot;: [&quot;Bash(rm -rf *)&quot;]</code>）就拦死，简洁，适合<strong>纯粹的「准入判断」</strong>。</li><li><strong>Hook</strong>：能跑一段脚本，除了「拦」还能<strong>顺手干别的</strong>——拦下的同时记个日志、发个通知、自动改写参数。适合 <strong>「拦 + 附带动作」或权限规则表达不了的复杂判断</strong>。</li></ul><p>一条好用的经验法则：<strong>「准不准」这种黑白判断，优先用权限规则，一行搞定；要在拦截那一刻顺带做点啥（记录、通知、改写），才上 Hook</strong>。两者不冲突，常常一起用——权限规则定基本盘，Hook 补那些「拦完还要再干一手」的活。</p><blockquote><p>💡 一句话总结：<strong>Skill 进我上下文 / Subagent 隔离只给结论；CLAUDE.md 每次看 / Skill 按需看；权限规则管「准不准」黑白判断 / Hook 管「拦截 + 附带动作」</strong>——三组分清，选择不再打架。</p></blockquote><hr><h2 id="_06-组合才是常态-单选题做久了-记得它们能叠" tabindex="-1">06 组合才是常态：单选题做久了，记得它们能叠 <a class="header-anchor" href="#_06-组合才是常态-单选题做久了-记得它们能叠" aria-label="Permalink to &quot;06 组合才是常态：单选题做久了，记得它们能叠&quot;">​</a></h2><p>到这儿你可能以为挑扩展点是道「单选题」。<strong>恰恰相反——真实项目里几乎全是组合。</strong> 每个扩展点干自己最擅长的那块，拼起来才是一套完整的「装备」。</p><p>官方给的几组经典搭配，每一组我都拿真实场景翻译一下：</p><table tabindex="0"><thead><tr><th>组合</th><th>怎么配合</th><th>落地长啥样</th></tr></thead><tbody><tr><td><strong>Skill + MCP</strong></td><td>MCP 负责「连上」，Skill 负责「教它用好」</td><td>MCP 接通数据库，Skill 写清你的表结构和常用查询套路</td></tr><tr><td><strong>Skill + Subagent</strong></td><td>Skill 里启动 Subagent 去并行干活</td><td>一个 <code>/audit</code> Skill 同时派出查安全、查性能、查风格三个 Subagent</td></tr><tr><td><strong>CLAUDE.md + Skill</strong></td><td>CLAUDE.md 放常驻规矩，Skill 放按需细则</td><td>CLAUDE.md 写「遵守我们的 API 约定」，Skill 里放那份完整风格指南</td></tr><tr><td><strong>Hook + MCP</strong></td><td>Hook 在某事件触发时，通过 MCP 干件外部的事</td><td>改完关键文件后，Hook 自动经 MCP 发条 Slack 通知</td></tr></tbody></table><p>看「Skill + MCP」这组就明白组合的妙处了：<strong>光有 MCP，Claude 能连上数据库，但它不懂你的表怎么设计、该怎么查最优；光有 Skill，它懂套路却连不上库</strong>。两个一叠，才是「既连得上、又用得好」。一个常用配置就是这么搭的——MCP 接好库，Skill 里写满「查用户订单走哪张表、统计口径是哪个字段」，配合起来 Claude 写出来的查询基本不用返工。</p><p>那一套组合好的配置，怎么搬到别的项目、或者分享给同事？<strong>答案是 Plugin（插件）——它是把这一切「打包带走」的那一层。</strong></p><p><strong>类比：行李箱。</strong> 你出门不会把衬衫、剃须刀、充电器一件件抱在怀里，你把它们<strong>统统码进一个箱子</strong>拎走。Plugin 就是这个箱子——把 Skill、Hook、Subagent、MCP server 一股脑装进一个可安装的单元，<strong>第二个项目要用同一套，装上这个 plugin 就齐了</strong>；里头的 Skill 还带命名空间（像 <code>/my-plugin:review</code>），多个 plugin 各装各的也不撞名。官方说得很直接：</p><blockquote><p>Plugin 将 skills、hooks、subagents 和 MCP servers 捆绑到单个可安装单元中。</p></blockquote><p>Plugin 的具体做法第 24 篇讲过，这里你只要记住它在体系里的位置：<strong>别的五个是「功能」，plugin 是「把功能装箱分发」的那层</strong>。</p><blockquote><p>💡 一句话总结：挑扩展点不是单选题——<strong>真实配置几乎都是组合</strong>（Skill+MCP、CLAUDE.md+Skill…）；想把一整套搬到别处或分享，用 <strong>Plugin 打成一个箱子带走</strong>。</p></blockquote><hr><h2 id="_07-动手-把一个真实需求清单-逐条「分诊」" tabindex="-1">07 动手：把一个真实需求清单，逐条「分诊」 <a class="header-anchor" href="#_07-动手-把一个真实需求清单-逐条「分诊」" aria-label="Permalink to &quot;07 动手：把一个真实需求清单，逐条「分诊」&quot;">​</a></h2><p>光看表不算会，得真上手「分诊」一遍。下面给你一份<strong>模拟的真实需求清单</strong>——这都是项目里会冒出来的真实念头。你的任务：照前面的决策树，给每一条挂对科室。<strong>这一节不用敲命令，是纯脑力练习，但它比记十条定义都管用。</strong></p><p><strong>第一步：把这份清单抄到你的备忘录里（或就在脑子里过）</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需求清单（给每条挑一个扩展点）：</span></span>
<span class="line"><span>A. 团队约定「一律用 pnpm，禁止 npm」，希望它每次都遵守</span></span>
<span class="line"><span>B. 想让它查公司内部的 PostgreSQL 数据库</span></span>
<span class="line"><span>C. 想敲一个命令就跑完「打 tag → 改 changelog → 推送」整套发版</span></span>
<span class="line"><span>D. 每次它编辑完任何文件，自动跑一遍 prettier 格式化</span></span>
<span class="line"><span>E. 让它一次性读完整个 utils 目录，只告诉我哪些函数没人用</span></span>
<span class="line"><span>F. 一份很长的「内部错误码对照表」，它偶尔需要查</span></span>
<span class="line"><span>G. 「生产数据库的迁移脚本，绝对不许它执行」，要硬拦死</span></span></code></pre></div><p><strong>第二步：自己先走一遍决策树，把答案写在每条后面</strong></p><p>别急着往下看，先用第 04 节那四个问题（连外部？要硬保证？要隔离？每次看还是按需看？）自己判一遍。</p><p><strong>第三步：对答案</strong></p><p>下面是参考答案和判断理由。<strong>对得上几条不重要，重要的是「为什么」对得上</strong>：</p><table tabindex="0"><thead><tr><th>需求</th><th>该用</th><th>判断理由（走了决策树哪条）</th></tr></thead><tbody><tr><td><strong>A</strong> 一律用 pnpm</td><td><strong>CLAUDE.md</strong></td><td>不连外部、不需脚本保证、不隔离；是「每次都看到」的规矩</td></tr><tr><td><strong>B</strong> 查内部数据库</td><td><strong>MCP</strong></td><td>第一问就命中：要连外部服务和数据</td></tr><tr><td><strong>C</strong> 一键发版</td><td><strong>slash command</strong></td><td>你主动触发的固定多步流程，给 Skill 配个 <code>/release</code></td></tr><tr><td><strong>D</strong> 编辑后自动格式化</td><td><strong>Hook</strong>（<code>PostToolUse</code>）</td><td>固定时机、要每次都跑、不需它思考</td></tr><tr><td><strong>E</strong> 读整个目录找死代码</td><td><strong>Subagent</strong></td><td>读一堆文件只要结论，隔离掉别塞爆主对话</td></tr><tr><td><strong>F</strong> 偶尔查错误码表</td><td><strong>Skill</strong></td><td>按需才看的参考资料，别塞 CLAUDE.md</td></tr><tr><td><strong>G</strong> 禁执行迁移脚本</td><td><strong>权限规则 / Hook</strong></td><td>要「保证」拦死，不能靠提示；纯准入判断优先权限规则</td></tr></tbody></table><p><strong>预期</strong>：如果你 A、F 没有混（一个进 CLAUDE.md、一个进 Skill），D、G 没有混（一个 Hook 自动跑、一个权限拦死），E 你选了 Subagent 而不是 Skill——<strong>那你这套「分诊」逻辑已经立起来了</strong>，以后真实需求来了照这个流程走就行。</p><p>哪条卡住了，回第 05 节翻对应的那组对比，多半就是那一对没分清。<strong>这套判断一般也得练上一阵才能形成肌肉记忆</strong>——头几次很容易把「该 Subagent 的活硬塞成 Skill」，跑两回发现主对话被中间过程灌爆，才记住「只要结论就派分身」。</p><blockquote><p>💡 一句话总结：拿一份真实需求清单<strong>逐条走决策树分诊</strong>，比背定义有用一百倍；卡住的那条，回去翻对应的「易混对比」基本就通了。</p></blockquote><hr><h2 id="_08-小结" tabindex="-1">08 小结 <a class="header-anchor" href="#_08-小结" aria-label="Permalink to &quot;08 小结&quot;">​</a></h2><p>这一篇给第四组收了口——把你一路学来的五大扩展点（外加 slash command），从「各是什么」翻转成「需求来了该用哪个」。</p><p>把核心串起来回顾：</p><table tabindex="0"><thead><tr><th>你心里那句话</th><th>该挂的科室</th><th>一句话关键点</th></tr></thead><tbody><tr><td>「每次都得遵守」</td><td><strong>CLAUDE.md</strong></td><td>始终生效的规矩，每会话自动加载，控制在 200 行内</td></tr><tr><td>「需要时自动调出 / 我一键触发」</td><td><strong>Skill / slash command</strong></td><td>按需的知识与流程，平时不占上下文</td></tr><tr><td>「连外部服务和数据」</td><td><strong>MCP</strong></td><td>内置工具够不着的，靠它接外部</td></tr><tr><td>「读一堆文件只给我结论」</td><td><strong>Subagent</strong></td><td>隔离上下文、并行专项，只返回摘要</td></tr><tr><td>「特定时机自动跑、要保证」</td><td><strong>Hook</strong></td><td>事件触发的确定动作，护栏级强制</td></tr><tr><td>「整套搬走 / 分享给别人」</td><td><strong>Plugin</strong></td><td>把上面这些打包成一个可安装单元</td></tr></tbody></table><p><strong>你现在应该能：</strong> 拿到任何一个「我想让 Claude……」的需求，不再对着五六个名词发懵——心里默念那四个问题（连外部？要硬保证？要隔离？每次看还是按需看？），顺着决策树走到叶子，直接锁定该用哪个；遇到 Skill vs Subagent、CLAUDE.md vs Skill、Hook vs 权限规则这种容易混的，也能讲清它俩到底差在哪。<strong>这套「需求 → 方案」的映射建起来，前面九篇学的零件才算真正盘活，能按需取用了。</strong></p><p>整个第四组（高级功能扩展）到这儿就齐了。<strong>五件兵器你都摸过了，也知道临阵该抽哪把——剩下的，就是把它们用顺。</strong></p><hr><p>下一篇起，进入第五组「系统配置与优化」。从 <strong>31「settings.json：用户级 / 项目级配置」</strong> 开打——这一路你写了 CLAUDE.md、配了权限、马上还要配 Hook，这些配置到底该写进哪个文件、用户级和项目级谁压谁，是时候规规矩矩安顿明白了。想想看：同一条配置，<strong>写在你的主目录和写在项目里，效果可能正好相反</strong>——这里头的门道，下一篇给你理清。</p>`,107)])])}const u=o(g,[["render",l]]);export{k as __pageData,u as default};
